// 识别所有章节标题（以"第 X 章"或数字编号开头如"1.1"、"1.1.1"等），并收集其段落 ID
var chapterIds = [];
var paragraphs = $paragraphs; // 假设已注入所有段落数据

for (var i = 0; i < paragraphs.length; i++) {
    var text = paragraphs[i].text.trim();
    if (!text) continue;

    // 匹配章节标题：以"第 X 章"或数字编号（如 1.1, 1.1.1）开头
    if (/^第 [零一二三四五六七八九十百千万]+章|^\\d+(\\.\\d+)*$/.test(text)) {
        chapterIds.push(paragraphs[i].id);
    }
}

return chapterIds;
